import{_ as e,o as a,c as r,a2 as n}from"./chunks/framework.CQMe4Urg.js";const c=JSON.parse('{"title":"第 9 章 Agent 框架","description":"","frontmatter":{},"headers":[],"relativePath":"09-frameworks/index.md","filePath":"09-frameworks/index.md","lastUpdated":1776333512000}'),o={name:"09-frameworks/index.md"};function i(h,t,d,l,g,s){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="第-9-章-agent-框架" tabindex="-1">第 9 章 Agent 框架 <a class="header-anchor" href="#第-9-章-agent-框架" aria-label="Permalink to &quot;第 9 章 Agent 框架&quot;">​</a></h1><p>当你从零手写 Agent 原型跑通之后，下一步就会面临一个经典问题：<strong>继续手写，还是上框架？</strong> 这一章帮你系统地回答这个问题，并带你走进主流框架的世界。</p><p>Agent 框架本质上是对「LLM + 工具调用 + 状态管理 + 可观测性」这套组合拳的封装。手写 50 行就能跑一个基本循环，但当你需要处理错误重试、多步工作流、状态持久化、Tracing 和成本追踪时，框架能帮你省下大量重复劳动。</p><p>当前主流的选择包括：<strong>LangChain</strong> 提供了最大的社区生态和丰富的集成；<strong>LangGraph</strong> 用状态图精确控制复杂工作流；<strong>CrewAI</strong> 让多角色协作变得直观；<strong>Anthropic Agent SDK</strong> 则走极简路线，保持最大灵活性。选择哪个取决于你的任务复杂度、团队偏好和性能要求。</p><p>当然，当现有框架无法满足你的生产需求时，<strong>自建框架</strong>也是一条可行的路。理解框架背后的核心抽象（Model Provider、Tool Registry、Memory Manager、Middleware Pipeline），你就能用 500 行代码搭出一个完全可控的轻量框架。</p><h2 id="本章内容" tabindex="-1">本章内容 <a class="header-anchor" href="#本章内容" aria-label="Permalink to &quot;本章内容&quot;">​</a></h2><table tabindex="0"><thead><tr><th>层级</th><th>内容</th><th>你将学到</th></tr></thead><tbody><tr><td><a href="./beginner.html">入门篇</a></td><td>为什么需要框架、选型指南、LangChain 核心概念</td><td>框架 vs 手写的决策方法，LangChain 快速上手</td></tr><tr><td><a href="./intermediate.html">进阶篇</a></td><td>LangGraph 工作流、CrewAI 多角色、Anthropic Agent SDK</td><td>三大框架的实战使用和对比</td></tr><tr><td><a href="./advanced.html">高级篇</a></td><td>框架源码分析、自建框架设计与完整实现</td><td>从原理到 500 行代码的 Mini Agent Framework</td></tr></tbody></table><h2 id="参考资源" tabindex="-1">参考资源 <a class="header-anchor" href="#参考资源" aria-label="Permalink to &quot;参考资源&quot;">​</a></h2><ul><li><a href="https://python.langchain.com/docs/" target="_blank" rel="noreferrer">LangChain Documentation</a> -- LangChain 官方文档</li><li><a href="https://langchain-ai.github.io/langgraph/" target="_blank" rel="noreferrer">LangGraph Documentation</a> -- LangGraph 官方文档</li><li><a href="https://docs.crewai.com/" target="_blank" rel="noreferrer">CrewAI Documentation</a> -- CrewAI 官方文档</li><li><a href="https://github.com/anthropics/anthropic-sdk-python" target="_blank" rel="noreferrer">Anthropic Agent SDK</a> -- Anthropic Python SDK</li><li><a href="https://github.com/openai/openai-agents-python" target="_blank" rel="noreferrer">OpenAI Agents SDK</a> -- OpenAI 官方 Agent 框架</li></ul>',9)])])}const m=e(o,[["render",i]]);export{c as __pageData,m as default};
